func TestMain(m *testing.M) {
	// run from project root
	_, filename, _, _ := runtime.Caller(0)
	dir := path.Join(path.Dir(filename), "../..")
	err := os.Chdir(dir)
	if err != nil {
		panic(err)
	}

	testManifestBytes, err = fileio.ReadFile(testIfc7ManifestPath)
	if err != nil {
		panic(err)
	}
	os.Exit(m.Run())
}

func TestLoad(t *testing.T) {
	// run from project root
	_, filename, _, _ := runtime.Caller(0)
	dir := path.Join(path.Dir(filename), "../..")
	err := os.Chdir(dir)
	if err != nil {
		t.Fatal(err)
	}
	project, err := Load()
	if err != nil {
		t.Fatal(err)
	}
	t.Logf("%+v", project)
}

func TestProject_Initialize(t *testing.T) {
	testutils.UseSandbox(t)
	for name, _ := range map[string]struct {
		expErr error
	}{
		"baseline": {
			expErr: nil,
		},
	} {
		t.Run(name, func(t *testing.T) {
			proj, err := New()
			if err != nil {
				t.Fatal(err)
			}
			if err = proj.Initialize(); err != nil {
				t.Fatal(err)
			}
			if !fileio.DirExists(internal.IfcFolder) {
				t.Fatalf("expected %s folder to exist after initialization", internal.IfcFolder)
			}
			if !fileio.FileExists(path.Join(internal.IfcFolder, internal.IfcManifestFile)) {
				t.Fatalf("expected %s file to exist after initialization", internal.IfcManifestFile)
			}
			if !fileio.FileExists(internal.IfcConfigFile) {
				t.Fatalf("expected %s file to exist after initialization", internal.IfcConfigFile)
			}
		})
	}
}

func TestProject_Use(t *testing.T) {
	for name, tc := range map[string]struct {
		config    Config
		manifest  Manifest
		useParams UseParams
		expConfig Config
		expErr    error
		setupMock func(ctrl *client.MockClientWithResponsesIfc)
	}{
		"baseline": {
			config:   Config{},
			manifest: mustParseManifest(t, testManifestBytes),
			useParams: UseParams{
				Ref: "dev.ifc7.dev/api/v0/ifc/orgs/ifc7/ifc7-rest",
			},
			expConfig: Config{
				Use: []Used{
					{
						Ref: "dev.ifc7.dev/api/v0/ifc/orgs/ifc7/ifc7-rest",
					},
				},
			},
			setupMock: func(mock *client.MockClientWithResponsesIfc) {
				mock.EXPECT().
					GetInterfaceByPathWithResponse(gomock.Any(), gomock.Eq(client.GetInterfaceByPathParamsOwnerScope("orgs")), gomock.Eq("ifc7"), gomock.Eq("ifc7-rest"), gomock.Any()).
					Return(&client.GetInterfaceByPathResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
					}, nil).
					AnyTimes()
			},
		},
		"invalid ref - bad format": {
			config:   Config{},
			manifest: mustParseManifest(t, testManifestBytes),
			useParams: UseParams{
				Ref: "invalid",
			},
			expErr: ErrInvalidRef,
		},
		"already using": {
			config: Config{
				Use: []Used{
					{
						Ref: "dev.ifc7.dev/api/v0/ifc/orgs/ifc7/ifc7-rest",
					},
				},
			},
			manifest: mustParseManifest(t, testManifestBytes),
			useParams: UseParams{
				Ref: "dev.ifc7.dev/api/v0/ifc/orgs/ifc7/ifc7-rest",
			},
			expErr: ErrRefExists,
			setupMock: func(mock *client.MockClientWithResponsesIfc) {
				mock.EXPECT().
					GetInterfaceByPathWithResponse(gomock.Any(), gomock.Eq(client.GetInterfaceByPathParamsOwnerScope("orgs")), gomock.Eq("ifc7"), gomock.Eq("ifc7-rest"), gomock.Any()).
					Return(&client.GetInterfaceByPathResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
					}, nil).
					AnyTimes()
			},
		},
	} {
		t.Run(name, func(t *testing.T) {
			proj, err := projectWithMockClient(t, tc.config, tc.manifest, tc.setupMock)
			if err != nil {
				t.Fatal(err)
			}
			err = proj.Use(t.Context(), tc.useParams)
			if endTest := testutils.CheckErr(t, err, tc.expErr); endTest == true {
				return
			}
			if !reflect.DeepEqual(proj.config, tc.expConfig) {
				t.Fatalf("expected config to be %v, got %v", tc.expConfig, proj.config)
			}
		})
	}
}

func TestProject_Add(t *testing.T) {
	for name, tc := range map[string]struct {
		config    Config
		manifest  Manifest
		addParams AddParams
		expConfig Config
		expErr    error
		setupMock func(ctrl *client.MockClientWithResponsesIfc)
	}{
		"baseline": {
			config:   Config{},
			manifest: mustParseManifest(t, testManifestBytes),
			addParams: AddParams{
				Name: "test-api",
				Path: "test-api.json",
			},
			expConfig: Config{
				Own: []Owned{
					{
						Name: "test-api",
						Path: "test-api.json",
					},
				},
			},
		},
		"already using name": {
			config: Config{
				Own: []Owned{
					{
						Name: "test-api",
						Path: "new-test-api.json",
					},
				},
			},
			manifest: mustParseManifest(t, testManifestBytes),
			addParams: AddParams{
				Name: "test-api",
				Path: "test-api.json",
			},
			expErr: ErrNameExists,
		},
		"already using path": {
			config: Config{
				Own: []Owned{
					{
						Name: "new-test-api",
						Path: "test-api.json",
					},
				},
			},
			manifest: mustParseManifest(t, testManifestBytes),
			addParams: AddParams{
				Name: "test-api",
				Path: "test-api.json",
			},
			expErr: ErrPathExists,
		},
	} {
		t.Run(name, func(t *testing.T) {
			proj, err := projectWithMockClient(t, tc.config, tc.manifest, tc.setupMock)
			if err != nil {
				t.Fatal(err)
			}
			err = proj.Add(t.Context(), tc.addParams)
			if endTest := testutils.CheckErr(t, err, tc.expErr); endTest == true {
				return
			}
			if !reflect.DeepEqual(proj.config, tc.expConfig) {
				t.Fatalf("expected config to be %v, got %v", tc.expConfig, proj.config)
			}
		})
	}
}

