func TestProject_Commit(t *testing.T) {
	for name, tc := range map[string]struct {
		config       Config
		manifest     Manifest
		commitParams CommitParams
		expErr       error
		setupMock    func(ctrl *client.MockClientWithResponsesIfc)
	}{
		"baseline": {
			config: Config{
				Own: []Owned{
					{
						Name: "ifc7-rest",
						Ref:  "dev.ifc7.dev/api/v0/ifc/orgs/ifc7/ifc7-rest",
						Path: testApiPath,
					},
				},
			},
			manifest:     mustParseManifest(t, testManifestBytes),
			commitParams: CommitParams{},
			setupMock: func(mock *client.MockClientWithResponsesIfc) {
				mock.EXPECT().
					GetInterfaceByPathWithResponse(gomock.Any(), gomock.Eq(client.GetInterfaceByPathParamsOwnerScope("orgs")), gomock.Eq("ifc7"), gomock.Eq("ifc7-rest"), gomock.Any()).
					Return(&client.GetInterfaceByPathResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
						JSON200: manifestInterface,
					}, nil).
					AnyTimes()
				mock.EXPECT().
					GetInterfaceWithResponse(gomock.Any(), gomock.Eq("interface_01kn3ma93qe59r0p8kw6821y2n"), gomock.Any()).
					Return(&client.GetInterfaceResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
						JSON200: manifestInterface,
					}, nil).
					AnyTimes()
				mock.EXPECT().
					ListInterfaceRevisionsWithResponse(gomock.Any(), gomock.Eq("interface_01kn3ma93qe59r0p8kw6821y2n")).
					Return(&client.ListInterfaceRevisionsResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
						JSON200: manifestRevisions,
					}, nil).
					AnyTimes()
				mock.EXPECT().
					ListInterfaceReleasesWithResponse(gomock.Any(), gomock.Eq("interface_01kn3ma93qe59r0p8kw6821y2n")).
					Return(&client.ListInterfaceReleasesResponse{
						HTTPResponse: &http.Response{
							StatusCode: http.StatusOK,
						},
						JSON200: manifestReleases,
					}, nil).
					AnyTimes()
			},
		},
	} {
		t.Run(name, func(t *testing.T) {
			proj, err := projectWithMockClient(t, tc.config, tc.manifest, tc.setupMock)
			if err != nil {
				t.Fatal(err)
			}
			err = proj.Commit(t.Context(), tc.commitParams)
			if endTest := testutils.CheckErr(t, err, tc.expErr); endTest == true {
				return
			}
			if len(proj.manifest.Interfaces) != 1 {
				t.Fatalf("expected 1 interface, got %d", len(proj.manifest.Interfaces))
			}
			for _, iface := range proj.manifest.Interfaces {
				if len(iface.Revisions) != 3 {
					t.Fatalf("expected 3 revisions, got %d", len(iface.Revisions))
				}
			}
		})
	}
}

