func mustParseManifest(t *testing.T, b []byte) Manifest {
	m := Manifest{}
	err := json.Unmarshal(b, &m)
	if err != nil {
		t.Fatal(err)
	}
	return m
}

func projectWithMockClient(t *testing.T, cfg Config, mft Manifest, setup func(ctrl *client.MockClientWithResponsesIfc)) (*Project, error) {
	ctrl := gomock.NewController(t)
	mock := client.NewMockClientWithResponsesIfc(ctrl)
	if setup != nil {
		setup(mock)
	}
	proj, err := New(func(p *Project) {
		p.client = mock
	})
	if err != nil {
		t.Fatal(err)
		return nil, err
	}
	proj.config = cfg
	proj.manifest = mft
	return proj, nil
}
